 37→
 38→	const { data: developers, isLoading } = useAnalyticsQuery(
 39→		orpc.analytics.developers.list.queryOptions({ input: { days } }),
 40→	);
 41→
 42→	const { data: trendsData } = useAnalyticsQuery(
 43→		orpc.analytics.developers.trends.queryOptions({ input: { days } }),
 44→	);
 45→
 46→	const { data: userMappings } = useAnalyticsQuery(
 47→		orpc.analytics.users.mappings.queryOptions({ input: { days: 30 } }),
 48→	);
 49→
 50→	const userMap = useMemo(() => {
 51→		const map = new Map<string, string>();
 52→		if (userMappings) {
 53→			for (const m of userMappings) {
 54→				map.set(m.user_id, m.username);
 55→			}
 56→		}
 57→		return map;
 58→	}, [userMappings]);
 59→
 60→	const userMapRecord = useMemo(() => Object.fromEntries(userMap), [userMap]);
 61→
 62→	const columns = useMemo<ColumnDef<DeveloperSummary>[]>(
 63→		() => [
 64→			{
 65→				accessorFn: (row) => formatUsername(row.user_id, userMapRecord),
 66→				id: "developer",
 67→				header: "Developer",
 68→				cell: ({ row }) => (
 69→					<div className="flex items-center">
 70→						<div className="flex-shrink-0 h-10 w-10 bg-blue-100 rounded-full flex items-center justify-center">
 71→							<span className="text-blue-600 font-semibold text-sm">
 72→								{formatUsername(row.original.user_id, userMapRecord)
 73→									.substring(0, 2)
 74→									.toUpperCase()}
 75→							</span>
 76→						</div>
 77→						<div className="ml-4">
 78→							<div className="text-sm font-medium text-foreground">
 79→								{formatUsername(row.original.user_id, userMapRecord)}
 80→							</div>
 81→						</div>
 82→					</div>
 83→				),
 84→			},
 85→			{
 86→				accessorKey: "total_sessions",
 87→				header: "Sessions",
 88→				cell: ({ row }) => (
 89→					<span className="text-muted">{row.original.total_sessions}</span>
 90→				),
 91→			},
 92→			{
 93→				accessorKey: "active_days",
 94→				header: "Active Days",
 95→				cell: ({ row }) => (
 96→					<span className="text-muted">{row.original.active_days}</span>
 97→				),
 98→			},
 99→			{
100→				accessorKey: "total_tokens",
101→				header: "Total Tokens",
102→				cell: ({ row }) => (
103→					<span className="text-muted">
104→						{(row.original.total_tokens / 1000).toFixed(0)}K
105→					</span>
106→				),
107→			},
108→			{
109→				accessorKey: "success_rate",
110→				header: "Success Rate",
111→				cell: ({ row }) => {
112→					const rate = row.original.success_rate;
113→					const color =
114→						rate >= 70
115→							? "text-status-success-icon"
116→							: rate >= 50
117→								? "text-status-warning-icon"
118→								: "text-status-error-icon";
119→					return (
120→						<span className={`font-medium ${color}`}>{rate.toFixed(0)}%</span>
121→					);
122→				},
123→			},
124→			{
125→				accessorKey: "cost",
126→				header: "Cost",
127→				cell: ({ row }) => (
128→					<span className="text-muted">${row.original.cost.toFixed(2)}</span>
129→				),
130→			},
131→			{
132→				accessorKey: "success_rate_trend",
133→				header: "Trend",
134→				cell: ({ row }) => {
135→					const trend = row.original.success_rate_trend;
136→					return (
137→						<div className="flex items-center">
138→							{trend > 0 && (
139→								<>
140→									<ArrowUp className="w-4 h-4 text-status-success-icon mr-1" />
141→									<span className="text-status-success-icon font-medium">
142→										+{trend.toFixed(0)}%
143→									</span>
144→								</>
145→							)}
146→							{trend < 0 && (
147→								<>
148→									<ArrowDown className="w-4 h-4 text-status-error-icon mr-1" />
149→									<span className="text-status-error-icon font-medium">
150→										{trend.toFixed(0)}%
151→									</span>
152→								</>
153→							)}
154→							{trend === 0 && (
155→								<>
156→									<Minus className="w-4 h-4 text-muted mr-1" />
157→									<span className="text-muted">0%</span>
158→								</>
159→							)}
160→						</div>
161→					);
162→				},
163→			},
164→			{
165→				accessorKey: "avg_session_duration_min",
166→				header: "Avg Session",
167→				cell: ({ row }) => (
168→					<span className="text-muted">
169→						{row.original.avg_session_duration_min.toFixed(0)}m
170→					</span>
171→				),
172→			},
173→			{
174→				accessorFn: (row) => new Date(row.last_active_date).getTime(),
175→				id: "last_active",
176→				header: "Last Active",
177→				cell: ({ row }) => (
178→					<span className="text-muted">
179→						{new Date(row.original.last_active_date).toLocaleDateString()}
180→					</span>
181→				),
182→			},
183→		],
184→		[userMapRecord],
185→	);
186→
187→	const totalSessions =
188→		developers?.reduce((sum, d) => sum + d.total_sessions, 0) ?? 0;
189→	const totalTokens =
190→		developers?.reduce((sum, d) => sum + d.total_tokens, 0) ?? 0;
191→	const totalHours =
192→		(developers?.reduce((sum, d) => sum + d.total_duration_min, 0) ?? 0) / 60;
193→
194→	if (isLoading) {
195→		return (
196→			<div className="px-8 py-6">
197→				<PageHeader
198→					title="Developers"
199→					description="Individual developer activity and metrics"
200→					actions={
201→						<DatePicker
202→							startDate={startDate}
203→							endDate={endDate}
204→							onStartDateChange={setStartDate}
205→							onEndDateChange={setEndDate}
206→						/>
207→					}
208→				/>
209→				<AnalyticsCard>
210→					<p className="text-center text-muted">Loading developers...</p>
211→				</AnalyticsCard>
212→			</div>
213→		);
214→	}
215→
216→	return (
217→		<div className="px-8 py-6">
218→			<PageHeader
219→				title="Developers"
220→				description="Individual developer activity and metrics"
221→				actions={
222→					<DatePicker
223→						startDate={startDate}
224→						endDate={endDate}
225→						onStartDateChange={setStartDate}
226→						onEndDateChange={setEndDate}
227→					/>
228→				}
229→			/>
230→
231→			{/* Summary Stats */}
232→			<div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-6 mb-8">
233→				<StatCard
234→					title="Team Members"
235→					value={memberCount ?? "..."}
236→					icon={Users}
237→					iconColor="text-blue-600"
238→				/>
239→				<StatCard
240→					title="Active Developers"
241→					value={developers?.length ?? 0}
242→					icon={UserCheck}
243→					iconColor="text-cyan-600"
244→				/>
245→				<StatCard
246→					title="Total Sessions"
247→					value={totalSessions.toLocaleString()}
248→					icon={Activity}
249→					iconColor="text-green-600"
250→				/>
251→				<StatCard
252→					title="Total Tokens"
253→					value={`${(totalTokens / 1000000).toFixed(1)}M`}
254→					icon={Code}
255→					iconColor="text-purple-600"
256→				/>
257→				<StatCard
258→					title="Total Hours"
259→					value={totalHours.toFixed(0)}
260→					icon={Clock}
261→					iconColor="text-orange-600"
262→				/>
263→			</div>
264→
265→			{/* Developers Table */}
266→			<AnalyticsCard>
267→				<h2 className="text-xl font-bold text-heading mb-4">Developer List</h2>
268→				<DataTable
269→					columns={columns}
270→					data={developers ?? []}
271→					defaultSorting={[{ id: "total_sessions", desc: true }]}
272→					onRowClick={(row) => navigate(`/dashboard/developers/${row.user_id}`)}
273→				/>
274→			</AnalyticsCard>
275→
276→			{/* Developer Trend Chart */}
277→			{trendsData && trendsData.length > 0 && (
278→				<AnalyticsCard className="mt-8">
279→					<h2 className="text-xl font-bold text-heading mb-4">
