281→					</h2>
282→					<p className="text-sm text-muted mb-6">
283→						Activity metrics over time split by developer
284→					</p>
285→					<DeveloperTrendChart data={trendsData} userMap={userMap} />
286→				</AnalyticsCard>
287→			)}
288→		</div>
289→	);
290→}
