  4→	getDeveloperDetails,
  5→	getDeveloperErrors,
  6→	getDeveloperFeatureUsage,
  7→	getDeveloperList,
  8→	getDeveloperProjects,
  9→	getDeveloperSessions,
 10→	getDeveloperTimeline,
 11→	getDeveloperTrends,
 12→} from "../../services/developer.service.js";
 13→
 14→const list = os.analytics.developers.list
 15→	.use(orgMiddleware)
 16→	.handler(async ({ input, context }) => {
 17→		return getDeveloperList(context.organizationId, input.days);
 18→	});
 19→
 20→const details = os.analytics.developers.details
 21→	.use(orgMiddleware)
