 40→			outcome: input.outcome,
 41→			limit: input.limit,
 42→			offset: input.offset,
 43→			sort_by: input.sortBy,
 44→			sort_order: input.sortOrder,
 45→		});
 46→	});
 47→
 48→const projects = os.analytics.developers.projects
 49→	.use(orgMiddleware)
 50→	.handler(async ({ input, context }) => {
 51→		return getDeveloperProjects(
 52→			context.organizationId,
 53→			input.userId,
 54→			input.days,
 55→		);
 56→	});
 57→
 58→const timeline = os.analytics.developers.timeline
 59→	.use(orgMiddleware)
 60→	.handler(async ({ input, context }) => {
 61→		return getDeveloperTimeline(
 62→			context.organizationId,
 63→			input.userId,
 64→			input.days,
 65→		);
 66→	});
 67→
 68→const features = os.analytics.developers.features
 69→	.use(orgMiddleware)
 70→	.handler(async ({ input, context }) => {
 71→		return getDeveloperFeatureUsage(
 72→			context.organizationId,
 73→			input.userId,
 74→			input.days,
 75→		);
 76→	});
 77→
 78→const errors = os.analytics.developers.errors
 79→	.use(orgMiddleware)
 80→	.handler(async ({ input, context }) => {
 81→		return getDeveloperErrors(context.organizationId, input.userId, input.days);
 82→	});
 83→
 84→const trends = os.analytics.developers.trends
 85→	.use(orgMiddleware)
 86→	.handler(async ({ input, context }) => {
 87→		return getDeveloperTrends(context.organizationId, input.days);
 88→	});
