 4→export function calculateCost(
 5→	inputTokens: number,
 6→	outputTokens: number,
 7→): number {
 8→	return (
 9→		(inputTokens / 1_000_000) * INPUT_PRICE_PER_MILLION +
10→		(outputTokens / 1_000_000) * OUTPUT_PRICE_PER_MILLION
11→	);
