 57→		median_response_time: "Median Response Time (sec)",
 58→		avg_tokens: "Avg Tokens",
 59→		total_tokens: "Total Tokens",
 60→		avg_success_score: "Avg Success Score",
 61→		avg_errors: "Avg Errors",
 62→		total_errors: "Total Errors",
 63→	};
 64→	return labelMap[metric] || metric;
 65→}
 66→
 67→function formatDimensionValue(
 68→	value: string,
 69→	dimension: string,
 70→	userMap?: Map<string, string>,
 71→): string {
 72→	if (
 73→		dimension === "has_commit" ||
 74→		dimension === "used_plan_mode" ||
 75→		dimension === "used_skills" ||
 76→		dimension === "used_slash_commands" ||
 77→		dimension === "used_subagents"
 78→	) {
 79→		return value === "1" ? "Yes" : "No";
 80→	}
 81→
 82→	if (dimension === "project_path") {
 83→		const parts = value.split("/");
 84→		return parts[parts.length - 1] || value;
 85→	}
 86→
 87→	if (dimension === "user_id") {
 88→		return formatUsername(value, Object.fromEntries(userMap || new Map()));
 89→	}
 90→
 91→	return value;
 92→}
 93→
 94→export const DimensionAnalysisChart = memo(function DimensionAnalysisChart({
 95→	data,
 96→	dimension,
 97→	metric,
 98→	split_by,
 99→	showPercentage = false,
100→	userMap,
101→}: DimensionAnalysisChartProps) {
102→	const { gridStroke, axisStroke } = useChartTheme();
103→
104→	const { chartData, dataKeys } = useMemo(() => {
105→		if (!data || data.length === 0) {
106→			return { chartData: [], dataKeys: [] };
107→		}
108→
109→		let chartData: Record<string, unknown>[] = [];
110→		let dataKeys: string[] = [];
111→
112→		if (split_by && data[0].split_values) {
113→			const allSplitValues = new Set<string>();
114→			for (const item of data) {
115→				if (item.split_values) {
116→					for (const key of Object.keys(item.split_values)) {
117→						allSplitValues.add(key);
118→					}
119→				}
120→			}
121→			dataKeys = Array.from(allSplitValues);
122→
123→			chartData = data.map((item) => {
124→				const row: Record<string, unknown> = {
125→					name: formatDimensionValue(item.dimension_value, dimension, userMap),
126→					_fullName: item.dimension_value,
127→					_total: 0,
128→					_originalValues: {} as Record<string, number>,
129→				};
130→				const origValues = row._originalValues as Record<string, number>;
131→				let total = 0;
132→				for (const key of dataKeys) {
133→					const val = item.split_values?.[key] || 0;
134→					origValues[key] = val;
135→					total += val;
136→				}
137→				row._total = total;
138→
139→				if (showPercentage && total > 0) {
140→					for (const key of dataKeys) {
141→						row[key] = (origValues[key] / total) * 100;
142→					}
143→				} else {
144→					for (const key of dataKeys) {
145→						row[key] = origValues[key];
146→					}
147→				}
148→
149→				return row;
150→			});

