387→								<SelectValue />
388→							</SelectTrigger>
389→							<SelectContent>
390→								<SelectItem value="none">None</SelectItem>
391→								<SelectItem value="session_archetype">Session Type</SelectItem>
392→								<SelectItem value="model_used">Model Used</SelectItem>
393→								<SelectItem value="user_id">User/Developer</SelectItem>
394→								<SelectItem value="repository">Repository</SelectItem>
395→							</SelectContent>
396→						</Select>
397→					</div>
398→				</div>
399→
400→				{selectedSplitBy && (
401→					<div className="mb-4 flex justify-end items-center gap-3">
402→						<span className="text-sm text-muted">
403→							{showPercentage ? "Showing as %" : "Showing absolute values"}
