425→						showPercentage={showPercentage}
426→						userMap={userMap}
427→					/>
428→				)}
429→			</AnalyticsCard>
430→
431→			{/* Sessions Table */}
432→			<AnalyticsCard>
433→				<div className="flex items-center justify-between mb-4">
434→					<div>
435→						<h3 className="text-lg font-semibold">
436→							Recent Sessions ({filteredSessions.length})
