import type {
	DimensionAnalysisInput,
	SessionAnalytics,
} from "@rudel/api-routes";
import type { ColumnDef } from "@tanstack/react-table";
import { Activity, Clock, Timer } from "lucide-react";
import { useEffect, useMemo, useState } from "react";
import { useNavigate } from "react-router-dom";
import { AnalyticsCard } from "@/components/analytics/AnalyticsCard";
import { DatePicker } from "@/components/analytics/DatePicker";
import { MultiSelect } from "@/components/analytics/MultiSelect";
import { PageHeader } from "@/components/analytics/PageHeader";
import { StatCard } from "@/components/analytics/StatCard";
import { DimensionAnalysisChart } from "@/components/charts/DimensionAnalysisChart";
import { DataTable } from "@/components/ui/data-table";
import {
	Select,
	SelectContent,
	SelectItem,
	SelectTrigger,
	SelectValue,
} from "@/components/ui/select";
import { Spinner } from "@/components/ui/spinner";
import { Switch } from "@/components/ui/switch";
import { useDateRange } from "@/contexts/DateRangeContext";
import { useAnalyticsQuery } from "@/hooks/useAnalyticsQuery";
import { calculateCost, formatUsername } from "@/lib/format";
import { orpc } from "@/lib/orpc";

export function SessionsListPage() {
	const navigate = useNavigate();
	const { startDate, endDate, setStartDate, setEndDate, calculateDays } =
		useDateRange();
	const days = calculateDays();

	const [selectedRepositories, setSelectedRepositories] = useState<string[]>(
		[],
	);
	const [selectedUsers, setSelectedUsers] = useState<string[]>([]);

	const [selectedDimension, setSelectedDimension] =
		useState<DimensionAnalysisInput["dimension"]>("repository");
	const [selectedMetric, setSelectedMetric] =
		useState<DimensionAnalysisInput["metric"]>("session_count");
	const [selectedSplitBy, setSelectedSplitBy] = useState<
		DimensionAnalysisInput["dimension"] | ""
	>("");
	const [showPercentage, setShowPercentage] = useState(false);

	const [debouncedDimension, setDebouncedDimension] =
		useState<DimensionAnalysisInput["dimension"]>("repository");
	const [debouncedMetric, setDebouncedMetric] =
		useState<DimensionAnalysisInput["metric"]>("session_count");
	const [debouncedSplitBy, setDebouncedSplitBy] = useState<
		DimensionAnalysisInput["dimension"] | ""
	>("");

	useEffect(() => {
		const timer = setTimeout(() => {
			setDebouncedDimension(selectedDimension);
			setDebouncedMetric(selectedMetric);
			setDebouncedSplitBy(selectedSplitBy);
		}, 300);
		return () => clearTimeout(timer);
	}, [selectedDimension, selectedMetric, selectedSplitBy]);

	const { data: summary } = useAnalyticsQuery(
		orpc.analytics.sessions.summary.queryOptions({ input: { days } }),
	);

	const { data: comparison } = useAnalyticsQuery(
		orpc.analytics.sessions.summaryComparison.queryOptions({
			input: { days },
		}),
	);

	const { data: sessions, isLoading } = useAnalyticsQuery(
		orpc.analytics.sessions.list.queryOptions({
			input: { days, limit: 100, sortBy: "session_date", sortOrder: "desc" },
		}),
	);

	const { data: userMappings } = useAnalyticsQuery(
		orpc.analytics.users.mappings.queryOptions({ input: { days: 30 } }),
	);

	const { data: dimensionData, isLoading: dimensionLoading } =
		useAnalyticsQuery(
			orpc.analytics.sessions.dimensionAnalysis.queryOptions({
				input: {
					days,
					dimension: debouncedDimension,
					metric: debouncedMetric,
					splitBy: debouncedSplitBy || undefined,
					limit: 10,
				},
			}),
		);

	const userMap = useMemo(() => {
		const map = new Map<string, string>();
		if (userMappings) {
			for (const m of userMappings) {
				map.set(m.user_id, m.username);
			}
		}
		return map;
	}, [userMappings]);

	const userMapRecord = useMemo(() => Object.fromEntries(userMap), [userMap]);

	const columns = useMemo<ColumnDef<SessionAnalytics>[]>(
		() => [
			{
				accessorKey: "session_id",
				header: "Session ID",
				cell: ({ row }) => (
					<span className="text-accent font-mono text-xs">
						{row.original.session_id.slice(0, 8)}...
					</span>
				),
			},
			{
				accessorFn: (row) => new Date(row.session_date).getTime(),
				id: "date",
				header: "Date",
				cell: ({ row }) => (
					<div>
						<span className="text-foreground">
							{new Date(row.original.session_date).toLocaleDateString()}
						</span>
						<br />
						<span className="text-xs text-muted">
							{new Date(row.original.session_date).toLocaleTimeString()}
						</span>
					</div>
				),
			},
			{
				accessorFn: (row) => formatUsername(row.user_id, userMapRecord),
				id: "user",
				header: "User",
				cell: ({ row }) => (
					<span className="text-subheading">
						{formatUsername(row.original.user_id, userMapRecord)}
					</span>
				),
			},
			{
				accessorKey: "project_path",
				header: "Project",
				cell: ({ row }) => (
					<div
						className="max-w-xs truncate"
						title={row.original.git_remote || row.original.project_path}
					>
						{row.original.git_remote
							? row.original.git_remote.split("/").pop()
							: row.original.project_path.split("/").pop() ||
								row.original.project_path}
					</div>
				),
			},
			{
				accessorKey: "duration_min",
				header: "Duration",
				cell: ({ row }) => (
					<span className="text-foreground">
						{row.original.duration_min.toFixed(0)} min
					</span>
				),
			},
			{
				accessorKey: "success_score",
				header: "Success Score",
				cell: ({ row }) => {
					const score = row.original.success_score;
					const color =
						score >= 70
							? "text-status-success-icon"
							: score >= 40
								? "text-status-warning-icon"
								: "text-status-error-icon";
					return (
						<>
							<span className={`font-semibold ${color}`}>
								{score.toFixed(0)}
							</span>
							<span className="text-xs text-muted"> / 100</span>
						</>
					);
				},
			},
			{
				accessorFn: (row) => calculateCost(row.input_tokens, row.output_tokens),
				id: "cost",
				header: "Cost",
				cell: ({ row }) => (
					<span className="text-foreground font-mono">
						$
						{calculateCost(
							row.original.input_tokens,
							row.original.output_tokens,
						).toFixed(4)}
					</span>
				),
			},
		],
		[userMapRecord],
	);

	const filteredSessions = useMemo(() => {
		if (!sessions) return [];
		return sessions.filter((session) => {
			const repoMatch =
				selectedRepositories.length === 0 ||
				(session.repository &&
					selectedRepositories.includes(session.repository));
			const userMatch =
				selectedUsers.length === 0 || selectedUsers.includes(session.user_id);
			return repoMatch && userMatch;
		});
	}, [sessions, selectedRepositories, selectedUsers]);

	const repositories = useMemo(() => {
		if (!sessions) return [];
		return Array.from(
			new Set(sessions.map((s) => s.repository).filter(Boolean)),
		).sort() as string[];
	}, [sessions]);

	const users = useMemo(() => {
		if (!sessions) return [];
		return Array.from(
			new Set(sessions.map((s) => s.user_id).filter(Boolean)),
		).sort();
	}, [sessions]);

	if (isLoading) {
		return (
			<div className="px-8 py-6">
				<PageHeader
					title="Sessions"
					description="Analyze session interaction timing and patterns"
					actions={
						<DatePicker
							startDate={startDate}
							endDate={endDate}
							onStartDateChange={setStartDate}
							onEndDateChange={setEndDate}
						/>
					}
				/>
				<AnalyticsCard>
					<p className="text-center text-muted">Loading session analytics...</p>
				</AnalyticsCard>
			</div>
		);
	}

	return (
		<div className="px-8 py-6">
			<PageHeader
				title="Sessions"
				description="Analyze session interaction timing and patterns"
				actions={
					<DatePicker
						startDate={startDate}
						endDate={endDate}
						onStartDateChange={setStartDate}
						onEndDateChange={setEndDate}
					/>
				}
			/>

			{summary && comparison && (
				<div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 mb-8">
					<StatCard
						title="Total Sessions"
						value={summary.total_sessions.toLocaleString()}
						icon={Activity}
						iconColor="text-blue-600"
						trend={{ value: comparison.changes.total_sessions }}
					/>
					<StatCard
						title="Avg Session Duration"
						value={`${summary.avg_session_duration_min.toFixed(1)} min`}
						icon={Clock}
						iconColor="text-purple-600"
						trend={{ value: comparison.changes.avg_session_duration_min }}
					/>
					<StatCard
						title="Avg Response Time"
						value={`${summary.avg_response_time_sec.toFixed(1)}s`}
						icon={Timer}
						iconColor="text-green-600"
						trend={{ value: comparison.changes.avg_response_time_sec }}
					/>
				</div>
			)}

			{/* Dimension Analysis */}
			<AnalyticsCard className="mb-8">
				<h3 className="text-lg font-semibold mb-4">
					Multi-Dimensional Analysis
				</h3>
				<p className="text-sm text-muted mb-6">
					Analyze sessions across different dimensions and metrics.
				</p>

				<div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-6">
					<div>
						<label
							htmlFor="sessions-metric-select"
							className="block text-sm font-medium text-subheading mb-2"
						>
							Measure (Y-Axis)
						</label>
						<Select
							value={selectedMetric}
							onValueChange={(v) =>
								setSelectedMetric(v as DimensionAnalysisInput["metric"])
							}
						>
							<SelectTrigger className="w-full">
								<SelectValue />
							</SelectTrigger>
							<SelectContent>
								<SelectItem value="session_count">Session Count</SelectItem>
								<SelectItem value="avg_duration">Avg Duration (min)</SelectItem>
								<SelectItem value="total_duration">
									Total Duration (hours)
								</SelectItem>
								<SelectItem value="avg_tokens">Avg Tokens</SelectItem>
								<SelectItem value="total_tokens">Total Tokens</SelectItem>
								<SelectItem value="avg_success_score">
									Avg Success Score
								</SelectItem>
								<SelectItem value="total_errors">Total Errors</SelectItem>
							</SelectContent>
						</Select>
					</div>
					<div>
						<label
							htmlFor="sessions-dimension-select"
							className="block text-sm font-medium text-subheading mb-2"
						>
							Group By (X-Axis)
						</label>
						<Select
							value={selectedDimension}
							onValueChange={(v) =>
								setSelectedDimension(v as DimensionAnalysisInput["dimension"])
							}
						>
							<SelectTrigger className="w-full">
								<SelectValue />
							</SelectTrigger>
							<SelectContent>
								<SelectItem value="session_archetype">Session Type</SelectItem>
								<SelectItem value="model_used">Model Used</SelectItem>
								<SelectItem value="user_id">User/Developer</SelectItem>
								<SelectItem value="project_path">Project</SelectItem>
								<SelectItem value="repository">Repository</SelectItem>
								<SelectItem value="has_commit">Has Commit</SelectItem>
							</SelectContent>
						</Select>
					</div>
					<div>
						<label
							htmlFor="sessions-splitby-select"
							className="block text-sm font-medium text-subheading mb-2"
						>
							Split By (Optional)
						</label>
						<Select
							value={selectedSplitBy || "none"}
							onValueChange={(v) => {
								const value = v === "none" ? "" : v;
								setSelectedSplitBy(
									value as DimensionAnalysisInput["dimension"] | "",
								);
								if (!value) setShowPercentage(false);
							}}
						>
							<SelectTrigger className="w-full">
								<SelectValue />
							</SelectTrigger>
							<SelectContent>
								<SelectItem value="none">None</SelectItem>
								<SelectItem value="session_archetype">Session Type</SelectItem>
								<SelectItem value="model_used">Model Used</SelectItem>
								<SelectItem value="user_id">User/Developer</SelectItem>
								<SelectItem value="repository">Repository</SelectItem>
							</SelectContent>
						</Select>
					</div>
				</div>

				{selectedSplitBy && (
					<div className="mb-4 flex justify-end items-center gap-3">
						<span className="text-sm text-muted">
							{showPercentage ? "Showing as %" : "Showing absolute values"}
						</span>
						<Switch
							checked={showPercentage}
							onCheckedChange={setShowPercentage}
						/>
					</div>
				)}

				{dimensionLoading ? (
					<div className="flex items-center justify-center h-64">
						<div className="text-center">
							<Spinner className="mb-2" />
							<p className="text-muted">Loading chart...</p>
						</div>
					</div>
				) : (
					<DimensionAnalysisChart
						data={dimensionData || []}
						dimension={selectedDimension}
						metric={selectedMetric}
						split_by={selectedSplitBy || undefined}
						showPercentage={showPercentage}
						userMap={userMap}
					/>
				)}
			</AnalyticsCard>

			{/* Sessions Table */}
			<AnalyticsCard>
				<div className="flex items-center justify-between mb-4">
					<div>
						<h3 className="text-lg font-semibold">
							Recent Sessions ({filteredSessions.length})
						</h3>
					</div>
					<div className="flex gap-3">
						<MultiSelect
							options={repositories}
							selected={selectedRepositories}
							onChange={setSelectedRepositories}
							placeholder="All Repositories"
							className="w-48"
						/>
						<MultiSelect
							options={users}
							selected={selectedUsers}
							onChange={setSelectedUsers}
							placeholder="All Developers"
							className="w-48"
						/>
					</div>
				</div>

				<DataTable
					columns={columns}
					data={filteredSessions}
					defaultSorting={[{ id: "date", desc: true }]}
					onRowClick={(row) =>
						navigate(`/dashboard/sessions/${row.session_id}`)
					}
				/>
			</AnalyticsCard>
		</div>
	);
}

import type { ProjectContributor, ProjectError } from "@rudel/api-routes";
import type { ColumnDef } from "@tanstack/react-table";
import { Activity, ArrowLeft, Clock, Code, Users, Zap } from "lucide-react";
import { useMemo } from "react";
import { Link, useParams } from "react-router-dom";
import {
	Bar,
	BarChart,
	CartesianGrid,
	Legend,
	ResponsiveContainer,
	Tooltip,
	XAxis,
	YAxis,
} from "recharts";
import { AnalyticsCard } from "@/components/analytics/AnalyticsCard";
import { DatePicker } from "@/components/analytics/DatePicker";
import { PageHeader } from "@/components/analytics/PageHeader";
import { StatCard } from "@/components/analytics/StatCard";
import { Button } from "@/components/ui/button";
import { DataTable } from "@/components/ui/data-table";
import { useDateRange } from "@/contexts/DateRangeContext";
import { useAnalyticsQuery } from "@/hooks/useAnalyticsQuery";
import { useChartTheme } from "@/hooks/useChartTheme";
import { decodeProjectPath, formatUsername } from "@/lib/format";
import { orpc } from "@/lib/orpc";

export function ProjectDetailPage() {
	const { projectPath: encodedProjectPath } = useParams<{
		projectPath: string;
	}>();
	const projectPath = decodeProjectPath(encodedProjectPath || "");
	const { startDate, endDate, setStartDate, setEndDate, calculateDays } =
		useDateRange();
	const chartTheme = useChartTheme();
	const days = calculateDays();

	const { data: details, isLoading } = useAnalyticsQuery(
		orpc.analytics.projects.details.queryOptions({
			input: { projectPath, days },
		}),
	);

	const { data: contributors } = useAnalyticsQuery(
		orpc.analytics.projects.contributors.queryOptions({
			input: { projectPath, days },
		}),
	);

	const { data: features } = useAnalyticsQuery(
		orpc.analytics.projects.features.queryOptions({
			input: { projectPath, days },
		}),
	);

	const { data: errors } = useAnalyticsQuery(
		orpc.analytics.projects.errors.queryOptions({
			input: { projectPath, days },
		}),
	);

	const { data: userMappings } = useAnalyticsQuery(
		orpc.analytics.users.mappings.queryOptions({ input: { days: 30 } }),
	);

	const userMapRecord = useMemo(() => {
		const record: Record<string, string> = {};
		if (userMappings) {
			for (const m of userMappings) {
				record[m.user_id] = m.username;
			}
		}
		return record;
	}, [userMappings]);

	const contributorChartData = useMemo(() => {
		if (!contributors) return [];
		return contributors.slice(0, 10).map((c) => ({
			name: formatUsername(c.user_id, userMapRecord),
			sessions: c.sessions,
			hours: parseFloat((c.total_duration_min / 60).toFixed(1)),
		}));
	}, [contributors, userMapRecord]);

	const contributorColumns = useMemo<ColumnDef<ProjectContributor>[]>(
		() => [
			{
				accessorFn: (row) => formatUsername(row.user_id, userMapRecord),
				id: "developer",
				header: "Developer",
				cell: ({ row }) => (
					<span className="font-medium text-foreground">
						{formatUsername(row.original.user_id, userMapRecord)}
					</span>
				),
			},
			{
				accessorKey: "sessions",
				header: "Sessions",
				cell: ({ row }) => (
					<span className="text-muted">{row.original.sessions}</span>
				),
			},
			{
				accessorKey: "contribution_percentage",
				header: "Contribution",
				cell: ({ row }) => (
					<span className="text-muted">
						{row.original.contribution_percentage.toFixed(0)}%
					</span>
				),
			},
			{
				accessorFn: (row) => row.total_duration_min,
				id: "total_time",
				header: "Total Time",
				cell: ({ row }) => (
					<span className="text-muted">
						{(row.original.total_duration_min / 60).toFixed(1)}h
					</span>
				),
			},
			{
				accessorKey: "total_tokens",
				header: "Tokens",
				cell: ({ row }) => (
					<span className="text-muted">
						{(row.original.total_tokens / 1000).toFixed(0)}K
					</span>
				),
			},
		],
		[userMapRecord],
	);

	const projectErrorColumns = useMemo<ColumnDef<ProjectError>[]>(
		() => [
			{
				accessorKey: "error_pattern",
				header: "Error Type",
				cell: ({ row }) => (
					<span className="font-medium text-foreground">
						{row.original.error_pattern}
					</span>
				),
			},
			{
				accessorKey: "occurrences",
				header: "Occurrences",
				cell: ({ row }) => (
					<span className="text-muted">{row.original.occurrences}</span>
				),
			},
			{
				accessorKey: "affected_users",
				header: "Affected Users",
				cell: ({ row }) => (
					<span className="text-muted">{row.original.affected_users}</span>
				),
			},
			{
				accessorFn: (row) => new Date(row.last_seen).getTime(),
				id: "last_seen",
				header: "Last Seen",
				cell: ({ row }) => (
					<span className="text-muted">
						{new Date(row.original.last_seen).toLocaleDateString()}
					</span>
				),
			},
		],
		[],
	);

	if (isLoading || !details) {
		return (
			<div className="px-8 py-6">
				<PageHeader
					title="Project Details"
					description="Loading project information..."
					actions={
						<Button variant="outline" size="sm" asChild>
							<Link to="/dashboard/projects">
								<ArrowLeft className="h-4 w-4" />
								Back to Projects
							</Link>
						</Button>
					}
				/>
				<AnalyticsCard>
					<p className="text-center text-muted">Loading...</p>
				</AnalyticsCard>
			</div>
		);
	}

	const projectName = projectPath.split("/").pop() || "Unknown Project";

	return (
		<div className="px-8 py-6">
			<PageHeader
				title={projectName}
				description="Project analytics and contributor insights"
				actions={
					<div className="flex items-center gap-3">
						<DatePicker
							startDate={startDate}
							endDate={endDate}
							onStartDateChange={setStartDate}
							onEndDateChange={setEndDate}
						/>
						<Button variant="outline" size="sm" asChild>
							<Link to="/dashboard/projects">
								<ArrowLeft className="h-4 w-4" />
								Back
							</Link>
						</Button>
					</div>
				}
			/>

			<div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
				<StatCard
					title="Total Sessions"
					value={details.total_sessions}
					icon={Activity}
					iconColor="text-blue-600"
				/>
				<StatCard
					title="Contributors"
					value={details.contributors_count}
					icon={Users}
					iconColor="text-green-600"
				/>
				<StatCard
					title="Total Tokens"
					value={`${(details.total_tokens / 1000000).toFixed(1)}M`}
					icon={Code}
					iconColor="text-purple-600"
				/>
				<StatCard
					title="Total Time"
					value={`${(details.total_duration_min / 60).toFixed(0)}h`}
					icon={Clock}
					iconColor="text-orange-600"
				/>
			</div>

			{features && (
				<div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
					<AnalyticsCard>
						<div className="flex items-center justify-between">
							<div>
								<p className="text-sm text-muted">Subagents</p>
								<p className="text-2xl font-bold text-heading">
									{features.subagents_adoption_rate.toFixed(0)}%
								</p>
							</div>
							<Zap className="h-8 w-8 text-blue-600" />
						</div>
					</AnalyticsCard>
					<AnalyticsCard>
						<div className="flex items-center justify-between">
							<div>
								<p className="text-sm text-muted">Skills</p>
								<p className="text-2xl font-bold text-heading">
									{features.skills_adoption_rate.toFixed(0)}%
								</p>
							</div>
							<Zap className="h-8 w-8 text-purple-600" />
						</div>
					</AnalyticsCard>
					<AnalyticsCard>
						<div className="flex items-center justify-between">
							<div>
								<p className="text-sm text-muted">Slash Commands</p>
								<p className="text-2xl font-bold text-heading">
									{features.slash_commands_adoption_rate.toFixed(0)}%
								</p>
							</div>
							<Zap className="h-8 w-8 text-green-600" />
						</div>
					</AnalyticsCard>
				</div>
			)}

			{contributorChartData.length > 0 && (
				<AnalyticsCard className="mb-8">
					<h2 className="text-xl font-bold text-heading mb-6">Contributors</h2>
					<ResponsiveContainer width="100%" height={350}>
						<BarChart data={contributorChartData} margin={{ bottom: 60 }}>
							<CartesianGrid
								strokeDasharray="3 3"
								stroke={chartTheme.gridStroke}
							/>
							<XAxis
								dataKey="name"
								angle={-45}
								textAnchor="end"
								height={80}
								interval={0}
								stroke={chartTheme.axisStroke}
							/>
							<YAxis yAxisId="left" stroke={chartTheme.axisStroke} />
							<YAxis
								yAxisId="right"
								orientation="right"
								stroke={chartTheme.axisStroke}
							/>
							<Tooltip
								contentStyle={{
									backgroundColor: chartTheme.tooltipBg,
									borderColor: chartTheme.tooltipBorder,
								}}
							/>
							<Legend />
							<Bar
								yAxisId="left"
								dataKey="sessions"
								fill="#3b82f6"
								name="Sessions"
							/>
							<Bar
								yAxisId="right"
								dataKey="hours"
								fill="#10b981"
								name="Hours"
							/>
						</BarChart>
					</ResponsiveContainer>
					{contributors && (
						<div className="mt-6">
							<DataTable
								columns={contributorColumns}
								data={contributors}
								defaultSorting={[{ id: "sessions", desc: true }]}
								defaultPageSize={50}
							/>
						</div>
					)}
				</AnalyticsCard>
			)}

			{errors && errors.length > 0 && (
				<AnalyticsCard className="mb-8">
					<h2 className="text-xl font-bold text-heading mb-4">
						Errors Encountered
					</h2>
					<DataTable
						columns={projectErrorColumns}
						data={errors}
						defaultSorting={[{ id: "occurrences", desc: true }]}
						defaultPageSize={50}
					/>
				</AnalyticsCard>
			)}
		</div>
	);
}

import type {
	DeveloperCostBreakdown,
	ProjectCostBreakdown,
} from "@rudel/api-routes";
import type { ColumnDef } from "@tanstack/react-table";
import {
	Activity,
	DollarSign,
	Target,
	TrendingDown,
	TrendingUp,
} from "lucide-react";
import { useMemo, useState } from "react";
import {
	CartesianGrid,
	Line,
	LineChart,
	ResponsiveContainer,
	Tooltip,
	XAxis,
	YAxis,
} from "recharts";
import { AnalyticsCard } from "@/components/analytics/AnalyticsCard";
import { DatePicker } from "@/components/analytics/DatePicker";
import { PageHeader } from "@/components/analytics/PageHeader";
import { StatCard } from "@/components/analytics/StatCard";
import { Button } from "@/components/ui/button";
import { DataTable } from "@/components/ui/data-table";
import { Input } from "@/components/ui/input";
import { Spinner } from "@/components/ui/spinner";
import { useDateRange } from "@/contexts/DateRangeContext";
import { useAnalyticsQuery } from "@/hooks/useAnalyticsQuery";
import { useChartTheme } from "@/hooks/useChartTheme";
import { formatUsername } from "@/lib/format";
import { orpc } from "@/lib/orpc";

export function ROIPage() {
	const { startDate, endDate, setStartDate, setEndDate, calculateDays } =
		useDateRange();
	const chartTheme = useChartTheme();
	const days = calculateDays();

	const [roiInputs, setRoiInputs] = useState({
		codePercentage: 65,
		tokensPerLOC: 15,
		locPerHour: 30,
		devHourlyRate: 100,
	});

	const { data: metrics, isLoading } = useAnalyticsQuery(
		orpc.analytics.roi.metrics.queryOptions({ input: { days } }),
	);

	const { data: trends } = useAnalyticsQuery(
		orpc.analytics.roi.trends.queryOptions({ input: { days: 56 } }),
	);

	const { data: developerCosts } = useAnalyticsQuery(
		orpc.analytics.roi.breakdownDevelopers.queryOptions({ input: { days } }),
	);

	const { data: projectCosts } = useAnalyticsQuery(
		orpc.analytics.roi.breakdownProjects.queryOptions({ input: { days } }),
	);

	const { data: userMappings } = useAnalyticsQuery(
		orpc.analytics.users.mappings.queryOptions({ input: { days: 90 } }),
	);

	const userMapRecord = useMemo(() => {
		const record: Record<string, string> = {};
		if (userMappings) {
			for (const m of userMappings) {
				record[m.user_id] = m.username;
			}
		}
		return record;
	}, [userMappings]);

	const devCostColumns = useMemo<ColumnDef<DeveloperCostBreakdown>[]>(
		() => [
			{
				accessorFn: (row) => formatUsername(row.user_id, userMapRecord),
				id: "developer",
				header: "Developer",
				cell: ({ row }) => (
					<span className="font-medium text-foreground">
						{formatUsername(row.original.user_id, userMapRecord)}
					</span>
				),
			},
			{
				accessorKey: "cost",
				header: "Cost",
				cell: ({ row }) => (
					<span className="text-right text-subheading">
						${row.original.cost.toFixed(2)}
					</span>
				),
			},
			{
				accessorKey: "sessions",
				header: "Sessions",
				cell: ({ row }) => (
					<span className="text-right text-subheading">
						{row.original.sessions}
					</span>
				),
			},
		],
		[userMapRecord],
	);

	const projectCostColumns = useMemo<ColumnDef<ProjectCostBreakdown>[]>(
		() => [
			{
				accessorKey: "project_path",
				header: "Project",
				cell: ({ row }) => (
					<span className="font-medium text-foreground truncate max-w-xs">
						{row.original.project_path.split("/").pop() ||
							row.original.project_path}
					</span>
				),
			},
			{
				accessorKey: "cost",
				header: "Cost",
				cell: ({ row }) => (
					<span className="text-right text-subheading">
						${row.original.cost.toFixed(2)}
					</span>
				),
			},
			{
				accessorKey: "sessions",
				header: "Sessions",
				cell: ({ row }) => (
					<span className="text-right text-subheading">
						{row.original.sessions}
					</span>
				),
			},
		],
		[],
	);

	const formatCurrency = (value: number) => `$${value.toFixed(2)}`;
	const formatPercent = (value: number) =>
		`${value >= 0 ? "+" : ""}${value.toFixed(1)}%`;

	const formatCompact = (value: number): string => {
		if (value >= 1_000_000) return `${(value / 1_000_000).toFixed(1)}M`;
		if (value >= 1_000) return `${(value / 1_000).toFixed(1)}K`;
		return value.toString();
	};

	const calculatedROI = useMemo(() => {
		if (!metrics) return null;
		const loc =
			(metrics.output_tokens * (roiInputs.codePercentage / 100)) /
			roiInputs.tokensPerLOC;
		const hoursSaved = loc / roiInputs.locPerHour;
		const valueCreated = hoursSaved * roiInputs.devHourlyRate;
		const dollarValueSaved = valueCreated - metrics.total_cost;
		const roiPercentage =
			metrics.total_cost > 0
				? (dollarValueSaved / metrics.total_cost) * 100
				: 0;

		return {
			loc: Math.round(loc),
			hoursSaved: parseFloat(hoursSaved.toFixed(2)),
			valueCreated: parseFloat(valueCreated.toFixed(2)),
			dollarValueSaved: parseFloat(dollarValueSaved.toFixed(2)),
			roiPercentage: parseFloat(roiPercentage.toFixed(2)),
		};
	}, [metrics, roiInputs]);

	const resetToDefaults = () => {
		setRoiInputs({
			codePercentage: 65,
			tokensPerLOC: 15,
			locPerHour: 30,
			devHourlyRate: 100,
		});
	};

	return (
		<div className="px-8 py-6">
			<PageHeader
				title="ROI & Business Value"
				description="Track return on investment and measure business impact of Claude Code"
				actions={
					<DatePicker
						startDate={startDate}
						endDate={endDate}
						onStartDateChange={setStartDate}
						onEndDateChange={setEndDate}
					/>
				}
			/>

			{isLoading && (
				<div className="flex items-center justify-center py-12">
					<div className="text-center">
						<Spinner size="lg" className="mb-4" />
						<p className="text-muted">Loading ROI data...</p>
					</div>
				</div>
			)}

			{!isLoading && metrics && calculatedROI && (
				<>
					{/* Input Configuration */}
					<AnalyticsCard className="mb-6">
						<div className="mb-4">
							<h3 className="text-lg font-semibold text-heading">
								ROI Calculation Parameters
							</h3>
							<p className="text-sm text-muted mt-1">
								Adjust inputs to explore different ROI scenarios
							</p>
						</div>
						<div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
							<div>
								<label
									htmlFor="codePercentage"
									className="block text-sm font-medium text-subheading mb-1"
								>
									Code Percentage (%)
								</label>
								<Input
									id="codePercentage"
									type="number"
									value={roiInputs.codePercentage}
									onChange={(e) =>
										setRoiInputs({
											...roiInputs,
											codePercentage: parseFloat(e.target.value) || 0,
										})
									}
									min={0}
									max={100}
								/>
								<p className="text-xs text-muted mt-1">
									% of output that is actual code
								</p>
							</div>
							<div>
								<label
									htmlFor="tokensPerLOC"
									className="block text-sm font-medium text-subheading mb-1"
								>
									Tokens per LOC
								</label>
								<Input
									id="tokensPerLOC"
									type="number"
									value={roiInputs.tokensPerLOC}
									onChange={(e) =>
										setRoiInputs({
											...roiInputs,
											tokensPerLOC: parseFloat(e.target.value) || 1,
										})
									}
									min={1}
								/>
								<p className="text-xs text-muted mt-1">
									Average tokens per line of code
								</p>
							</div>
							<div>
								<label
									htmlFor="locPerHour"
									className="block text-sm font-medium text-subheading mb-1"
								>
									LOC per Hour (baseline)
								</label>
								<Input
									id="locPerHour"
									type="number"
									value={roiInputs.locPerHour}
									onChange={(e) =>
										setRoiInputs({
											...roiInputs,
											locPerHour: parseFloat(e.target.value) || 1,
										})
									}
									min={1}
								/>
								<p className="text-xs text-muted mt-1">
									Manual coding speed without Claude
								</p>
							</div>
							<div>
								<label
									htmlFor="devHourlyRate"
									className="block text-sm font-medium text-subheading mb-1"
								>
									Developer Rate ($/hr)
								</label>
								<Input
									id="devHourlyRate"
									type="number"
									value={roiInputs.devHourlyRate}
									onChange={(e) =>
										setRoiInputs({
											...roiInputs,
											devHourlyRate: parseFloat(e.target.value) || 1,
										})
									}
									min={1}
								/>
								<p className="text-xs text-muted mt-1">Hourly developer cost</p>
							</div>
						</div>
						<div className="mt-4">
							<Button variant="outline" size="sm" onClick={resetToDefaults}>
								Reset to Defaults
							</Button>
						</div>
					</AnalyticsCard>

					{/* KPI Cards */}
					<div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
						<StatCard
							title="Total Spend"
							value={formatCurrency(metrics.total_cost)}
							icon={DollarSign}
							iconColor="text-red-600"
							trend={{ value: metrics.total_cost_change_pct }}
						/>
						<StatCard
							title="Cost per Commit"
							value={
								metrics.cost_per_commit > 0
									? formatCurrency(metrics.cost_per_commit)
									: "N/A"
							}
							icon={Target}
							iconColor="text-blue-600"
							trend={{ value: metrics.cost_per_commit_change_pct }}
						/>
						<StatCard
							title="Dev Hours Saved"
							value={`${formatCompact(calculatedROI.hoursSaved)}h`}
							icon={Activity}
							iconColor="text-green-600"
							trend={{ value: metrics.dev_hours_saved_change_pct }}
						/>
						<StatCard
							title="Dollar Value Saved"
							value={`$${formatCompact(calculatedROI.dollarValueSaved)}`}
							icon={
								calculatedROI.roiPercentage >= 0 ? TrendingUp : TrendingDown
							}
							iconColor={
								calculatedROI.roiPercentage >= 0
									? "text-green-600"
									: "text-red-600"
							}
						/>
					</div>

					{/* ROI Breakdown */}
					<AnalyticsCard className="mb-8">
						<div className="mb-4">
							<h3 className="text-lg font-semibold text-heading">
								ROI Calculation Breakdown
							</h3>
						</div>
						<div className="bg-surface rounded-lg p-6 font-mono text-sm">
							<div className="space-y-2">
								<div className="flex justify-between">
									<span className="text-muted">Output Tokens:</span>
									<span className="font-semibold text-foreground">
										{formatCompact(metrics.output_tokens)}
									</span>
								</div>
								<div className="flex justify-between">
									<span className="text-muted">
										Code % ({roiInputs.codePercentage}%):
									</span>
									<span className="font-semibold text-foreground">
										{formatCompact(calculatedROI.loc)} LOC
									</span>
								</div>
								<div className="flex justify-between border-b border-border pb-2">
									<span className="text-muted">
										Hours Saved (LOC / {roiInputs.locPerHour}):
									</span>
									<span className="font-semibold text-foreground">
										{formatCompact(calculatedROI.hoursSaved)} hours
									</span>
								</div>
								<div className="pt-2 space-y-2">
									<div className="flex justify-between">
										<span className="text-muted">Value Created:</span>
										<span className="font-semibold text-status-success-icon">
											${formatCompact(calculatedROI.valueCreated)}
										</span>
									</div>
									<div className="flex justify-between">
										<span className="text-muted">Token Cost:</span>
										<span className="font-semibold text-status-error-icon">
											-{formatCurrency(metrics.total_cost)}
										</span>
									</div>
									<div className="flex justify-between border-t-2 border-border pt-2 mt-2">
										<span className="text-foreground font-bold">
											Net Value:
										</span>
										<span className="font-bold text-accent text-lg">
											${formatCompact(calculatedROI.dollarValueSaved)}
										</span>
									</div>
									<div className="flex justify-between">
										<span className="text-foreground font-bold">ROI:</span>
										<span
											className={`font-bold text-lg ${
												calculatedROI.roiPercentage >= 0
													? "text-status-success-icon"
													: "text-status-error-icon"
											}`}
										>
											{formatPercent(calculatedROI.roiPercentage)}
										</span>
									</div>
								</div>
							</div>
						</div>
					</AnalyticsCard>

					{/* Trends Charts */}
					{trends && trends.length > 0 && (
						<div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8">
							<AnalyticsCard>
								<div className="mb-4">
									<h3 className="text-lg font-semibold text-heading">
										Weekly Cost Trend
									</h3>
									<p className="text-sm text-muted mt-1">
										Total spend over time
									</p>
								</div>
								<ResponsiveContainer width="100%" height={300}>
									<LineChart data={trends}>
										<CartesianGrid
											strokeDasharray="3 3"
											stroke={chartTheme.gridStroke}
										/>
										<XAxis
											dataKey="week_start"
											stroke={chartTheme.axisStroke}
											fontSize={12}
											tickFormatter={(value) =>
												new Date(value).toLocaleDateString("en-US", {
													month: "short",
													day: "numeric",
												})
											}
										/>
										<YAxis
											stroke={chartTheme.axisStroke}
											fontSize={12}
											tickFormatter={(value) => `$${value}`}
										/>
										<Tooltip
											contentStyle={{
												backgroundColor: chartTheme.tooltipBg,
												borderColor: chartTheme.tooltipBorder,
											}}
											formatter={(value) => [
												`$${((value as number) ?? 0).toFixed(2)}`,
												"Cost",
											]}
											labelFormatter={(label) =>
												`Week of ${new Date(label).toLocaleDateString()}`
											}
										/>
										<Line
											type="monotone"
											dataKey="total_cost"
											stroke="#3b82f6"
											strokeWidth={2}
											dot={{ r: 4 }}
										/>
									</LineChart>
								</ResponsiveContainer>
							</AnalyticsCard>

							<AnalyticsCard>
								<div className="mb-4">
									<h3 className="text-lg font-semibold text-heading">
										Weekly Productivity Score
									</h3>
									<p className="text-sm text-muted mt-1">
										Commits per dollar x 100
									</p>
								</div>
								<ResponsiveContainer width="100%" height={300}>
									<LineChart data={trends}>
										<CartesianGrid
											strokeDasharray="3 3"
											stroke={chartTheme.gridStroke}
										/>
										<XAxis
											dataKey="week_start"
											stroke={chartTheme.axisStroke}
											fontSize={12}
											tickFormatter={(value) =>
												new Date(value).toLocaleDateString("en-US", {
													month: "short",
													day: "numeric",
												})
											}
										/>
										<YAxis stroke={chartTheme.axisStroke} fontSize={12} />
										<Tooltip
											contentStyle={{
												backgroundColor: chartTheme.tooltipBg,
												borderColor: chartTheme.tooltipBorder,
											}}
											labelFormatter={(label) =>
												`Week of ${new Date(label).toLocaleDateString()}`
											}
										/>
										<Line
											type="monotone"
											dataKey="productivity_score"
											stroke="#10b981"
											strokeWidth={2}
											dot={{ r: 4 }}
											name="Productivity Score"
										/>
									</LineChart>
								</ResponsiveContainer>
							</AnalyticsCard>
						</div>
					)}

					{/* Cost Breakdown Tables */}
					<div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
						<AnalyticsCard>
							<h3 className="text-lg font-semibold text-heading mb-4">
								Developer Cost Breakdown
							</h3>
							<DataTable
								columns={devCostColumns}
								data={developerCosts ?? []}
								defaultSorting={[{ id: "cost", desc: true }]}
								defaultPageSize={50}
							/>
						</AnalyticsCard>

						<AnalyticsCard>
							<h3 className="text-lg font-semibold text-heading mb-4">
								Project Cost Breakdown
							</h3>
							<DataTable
								columns={projectCostColumns}
								data={projectCosts ?? []}
								defaultSorting={[{ id: "cost", desc: true }]}
								defaultPageSize={50}
							/>
						</AnalyticsCard>
					</div>
				</>
			)}
		</div>
	);
}

