import { BookOpen, FolderKanban, Lightbulb, Users } from "lucide-react";
import { useMemo, useState } from "react";
import { AnalyticsCard } from "@/components/analytics/AnalyticsCard";
import { DatePicker } from "@/components/analytics/DatePicker";
import { MultiSelect } from "@/components/analytics/MultiSelect";
import { PageHeader } from "@/components/analytics/PageHeader";
import { StatCard } from "@/components/analytics/StatCard";
import { LearningsTrendChart } from "@/components/charts/LearningsTrendChart";
import { LearningsTimeline } from "@/components/learnings/LearningsTimeline";
import { useDateRange } from "@/contexts/DateRangeContext";
import { useAnalyticsQuery } from "@/hooks/useAnalyticsQuery";
import { orpc } from "@/lib/orpc";

export function LearningsPage() {
	const { startDate, endDate, setStartDate, setEndDate, calculateDays } =
		useDateRange();
	const days = calculateDays();

	const [splitBy, setSplitBy] = useState<"user_id" | "repository">("user_id");
	const [selectedUsers, setSelectedUsers] = useState<string[]>([]);
	const [selectedProjects, setSelectedProjects] = useState<string[]>([]);

	const { data: learnings, isLoading } = useAnalyticsQuery(
		orpc.analytics.learnings.list.queryOptions({
			input: { days, limit: 100, offset: 0 },
		}),
	);

	const { data: stats } = useAnalyticsQuery(
		orpc.analytics.learnings.stats.queryOptions({ input: { days } }),
	);

	const { data: trendData } = useAnalyticsQuery(
		orpc.analytics.learnings.trend.queryOptions({
			input: { days, splitBy },
		}),
	);

	const { data: availableUsers } = useAnalyticsQuery(
		orpc.analytics.learnings.users.queryOptions({}),
	);

	const { data: availableProjects } = useAnalyticsQuery(
		orpc.analytics.learnings.projects.queryOptions({}),
	);

	const { data: userMappings } = useAnalyticsQuery(
		orpc.analytics.users.mappings.queryOptions({ input: { days: 30 } }),
	);

	const userMap = useMemo(() => {
		const map = new Map<string, string>();
		if (userMappings) {
			for (const m of userMappings) {
				map.set(m.user_id, m.username);
			}
		}
		return map;
	}, [userMappings]);

	const userDisplayOptions = useMemo(() => {
		if (!availableUsers) return [];
		return availableUsers.map(
			(userId) => userMap.get(userId) || `${userId.substring(0, 8)}...`,
		);
	}, [availableUsers, userMap]);

	const projectDisplayOptions = useMemo(() => {
		if (!availableProjects) return [];
		return availableProjects.map((path) => {
			const name = path.split("/").pop() || path;
			return name;
		});
	}, [availableProjects]);

	const filteredLearnings = useMemo(() => {
		if (!learnings) return [];
		return learnings.filter((learning) => {
			if (
				selectedUsers.length > 0 &&
				!selectedUsers.includes(learning.user_id)
			) {
				return false;
			}
			if (
				selectedProjects.length > 0 &&
				!selectedProjects.includes(learning.project_path)
			) {
				return false;
			}
			return true;
		});
	}, [learnings, selectedUsers, selectedProjects]);

	const handleUserFilterChange = (selectedNames: string[]) => {
		if (!availableUsers) return;
		const userIds = selectedNames.map((name) => {
			const userId = availableUsers.find(
				(id) => (userMap.get(id) || `${id.substring(0, 8)}...`) === name,
			);
			return userId || name;
		});
		setSelectedUsers(userIds);
	};

	const handleProjectFilterChange = (selected: string[]) => {
		if (!availableProjects) return;
		const fullPaths = selected.map((name) => {
			const path = availableProjects.find((p) => p.split("/").pop() === name);
			return path || name;
		});
		setSelectedProjects(fullPaths);
	};

	const hasData = !isLoading && stats != null && stats.total_learnings > 0;

	return (
		<div className="px-8 py-6">
			<PageHeader
				title="Learning Feed"
				description="Team feedback and insights from /compound:feedback sessions"
				actions={
					hasData ? (
						<DatePicker
							startDate={startDate}
							endDate={endDate}
							onStartDateChange={setStartDate}
							onEndDateChange={setEndDate}
						/>
					) : undefined
				}
			/>

			{!isLoading && !hasData && (
				<AnalyticsCard className="mt-4">
					<div className="flex flex-col items-center justify-center py-20 px-4 text-center">
						<div className="w-16 h-16 rounded-full bg-muted flex items-center justify-center mb-6">
							<Lightbulb className="w-8 h-8 text-muted-foreground" />
						</div>
						<h3 className="text-lg font-semibold text-foreground mb-3">
							No learnings yet
						</h3>
						<p className="text-sm text-muted-foreground max-w-lg mb-6">
							This feature is powered by our internal continuous improvement
							system at{" "}
							<a
								href="https://obsessiondb.com"
								target="_blank"
								rel="noopener noreferrer"
								className="text-foreground underline underline-offset-2 hover:text-foreground/80"
							>
								ObsessionDB
							</a>
							. We are working on open-sourcing this workflow so you can set up
							your own continuous improvement agent system for your team.
						</p>
						<p className="text-xs text-muted-foreground/60 max-w-md">
							Stay tuned — once available, learnings will automatically appear
							here as your team captures feedback during coding sessions.
						</p>
					</div>
				</AnalyticsCard>
			)}

			{hasData && (
				<>
					{/* Stats Overview */}
					{stats && (
						<div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
							<StatCard
								title="Total Learnings"
								value={stats.total_learnings.toString()}
								icon={BookOpen}
								subtitle={`${stats.learnings_by_day.length} days with feedback`}
							/>
							<StatCard
								title="Team Members"
								value={stats.unique_users.toString()}
								icon={Users}
								subtitle="Contributing feedback"
							/>
							<StatCard
								title="Projects"
								value={stats.unique_projects.toString()}
								icon={FolderKanban}
								subtitle="With learnings captured"
							/>
						</div>
					)}

					{/* Filters */}
					<div className="mb-6 flex flex-wrap gap-4">
						<MultiSelect
							options={userDisplayOptions}
							selected={selectedUsers.map(
								(userId) =>
									userMap.get(userId) || `${userId.substring(0, 8)}...`,
							)}
							onChange={handleUserFilterChange}
							placeholder="All Users"
							className="w-64"
						/>
						<MultiSelect
							options={projectDisplayOptions}
							selected={selectedProjects.map((path) => {
								const name = path.split("/").pop() || path;
								return name;
							})}
							onChange={handleProjectFilterChange}
							placeholder="All Projects"
							className="w-64"
						/>
						{(selectedUsers.length > 0 || selectedProjects.length > 0) && (
							<button
								type="button"
								onClick={() => {
									setSelectedUsers([]);
									setSelectedProjects([]);
								}}
								className="px-4 py-2 text-sm text-muted hover:text-foreground hover:bg-hover rounded-md transition-colors"
							>
								Clear filters
							</button>
						)}
					</div>

					{/* Learnings Trend Chart */}
					{trendData && trendData.length > 0 && (
						<AnalyticsCard className="mb-6">
							<h2 className="text-xl font-bold text-heading mb-4">
								Learnings Over Time
							</h2>
							<p className="text-sm text-muted mb-6">
								Feedback activity over time split by developer
							</p>
							<LearningsTrendChart
								data={trendData}
								splitBy={splitBy}
								onSplitByChange={setSplitBy}
								userMap={userMap}
							/>
						</AnalyticsCard>
					)}

					{/* Timeline */}
					<AnalyticsCard>
						<div className="p-6">
							{filteredLearnings.length > 0 && (
								<div className="flex items-center justify-end mb-6">
									<span className="text-sm text-muted">
										{filteredLearnings.length}{" "}
										{filteredLearnings.length === 1 ? "learning" : "learnings"}
									</span>
								</div>
							)}

							<LearningsTimeline
								learnings={filteredLearnings}
								isLoading={isLoading}
								userMap={Object.fromEntries(userMap)}
							/>
						</div>
					</AnalyticsCard>
				</>
			)}
		</div>
	);
}

import { AlertCircle, AlertTriangle, Clock, Users } from "lucide-react";
import { useMemo, useState } from "react";
import { AnalyticsCard } from "@/components/analytics/AnalyticsCard";
import { DatePicker } from "@/components/analytics/DatePicker";
import { PageHeader } from "@/components/analytics/PageHeader";
import { StatCard } from "@/components/analytics/StatCard";
import { ErrorTrendChart } from "@/components/charts/ErrorTrendChart";
import { useDateRange } from "@/contexts/DateRangeContext";
import { useAnalyticsQuery } from "@/hooks/useAnalyticsQuery";
import { orpc } from "@/lib/orpc";

const severityColors = {
	high: "bg-status-error-bg text-status-error-text border-status-error-border",
	medium:
		"bg-status-warning-bg text-status-warning-text border-status-warning-border",
	low: "bg-status-info-bg text-status-info-text border-status-info-border",
};

const severityIcons = {
	high: "\u{1F534}",
	medium: "\u{1F7E1}",
	low: "\u{1F535}",
};

export function ErrorsPage() {
	const { startDate, endDate, setStartDate, setEndDate, calculateDays } =
		useDateRange();
	const days = calculateDays();

	const [trendMetric, setTrendMetric] = useState<
		"avg_errors_per_interaction" | "avg_errors_per_session" | "total_errors"
	>("total_errors");
	const [trendSplitBy, setTrendSplitBy] = useState<
		"repository" | "user_id" | "model"
	>("repository");

	const { data: errors, isLoading } = useAnalyticsQuery(
		orpc.analytics.errors.topRecurring.queryOptions({
			input: { days, minOccurrences: 2, limit: 15 },
		}),
	);

	const { data: trendData, isLoading: trendLoading } = useAnalyticsQuery(
		orpc.analytics.errors.trends.queryOptions({
			input: { startDate, endDate, splitBy: trendSplitBy },
		}),
	);

	const { data: userMappings } = useAnalyticsQuery(
		orpc.analytics.users.mappings.queryOptions({ input: { days: 30 } }),
	);

	const userMap = useMemo(() => {
		const map = new Map<string, string>();
		if (userMappings) {
			for (const m of userMappings) {
				map.set(m.user_id, m.username);
			}
		}
		return map;
	}, [userMappings]);

	const totalErrors = errors?.reduce((sum, e) => sum + e.occurrences, 0) ?? 0;
	const highSeverityCount =
		errors?.filter((e) => e.severity === "high").length ?? 0;
	const affectedUsersTotal =
		errors && errors.length > 0
			? Math.max(...errors.map((e) => e.affected_users))
			: 0;
	const mostCommonError =
		errors && errors.length > 0 ? errors[0].error_pattern : "None";

	if (isLoading) {
		return (
			<div className="px-8 py-6">
				<PageHeader
					title="Error Intelligence"
					description="Track and analyze recurring errors across your team"
					actions={
						<DatePicker
							startDate={startDate}
							endDate={endDate}
							onStartDateChange={setStartDate}
							onEndDateChange={setEndDate}
						/>
					}
				/>
				<AnalyticsCard>
					<p className="text-center text-muted">Loading error data...</p>
				</AnalyticsCard>
			</div>
		);
	}

	return (
		<div className="px-8 py-6">
			<PageHeader
				title="Error Intelligence"
				description="Track and analyze recurring errors across your team"
				actions={
					<DatePicker
						startDate={startDate}
						endDate={endDate}
						onStartDateChange={setStartDate}
						onEndDateChange={setEndDate}
					/>
				}
			/>

			{/* Summary Stats */}
			<div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
				<StatCard
					title="Total Errors"
					value={totalErrors.toLocaleString()}
					subtitle="error occurrences"
					icon={AlertCircle}
					iconColor="text-red-600"
				/>
				<StatCard
					title="High Severity"
					value={highSeverityCount}
					subtitle="critical issues"
					icon={AlertTriangle}
					iconColor="text-orange-600"
				/>
				<StatCard
					title="Most Common"
					value={mostCommonError}
					subtitle="top error type"
					icon={Clock}
					iconColor="text-purple-600"
				/>
				<StatCard
					title="Max Affected Users"
					value={affectedUsersTotal}
					subtitle="developers impacted"
					icon={Users}
					iconColor="text-blue-600"
				/>
			</div>

			{/* Error Trends Chart */}
			<AnalyticsCard className="mb-8">
				<h2 className="text-xl font-bold text-heading mb-2">
					Error Trends Over Time
				</h2>
				<p className="text-sm text-muted mb-6">
					Track error metrics across different dimensions to identify patterns
					and trends
				</p>
				{trendLoading ? (
					<div className="text-center py-12 text-muted">
						Loading error trends...
					</div>
				) : (
					<ErrorTrendChart
						data={trendData || []}
						metric={trendMetric}
						splitBy={trendSplitBy}
						onMetricChange={setTrendMetric}
						onSplitByChange={setTrendSplitBy}
						userMap={userMap}
					/>
				)}
			</AnalyticsCard>

			{/* Top Recurring Errors */}
			<AnalyticsCard className="mb-8">
				<h2 className="text-xl font-bold text-heading mb-4">
					Top Recurring Errors
				</h2>
				<p className="text-sm text-muted mb-6">
					Most frequently occurring errors that may need attention
				</p>
				{errors && errors.length > 0 ? (
					<div className="space-y-4">
						{errors.map((err, index) => (
							<div
								// biome-ignore lint/suspicious/noArrayIndexKey: static list of errors
								key={index}
								className="border border-border rounded-lg p-4 hover:shadow-md transition-shadow"
							>
								<div className="flex items-start justify-between">
									<div className="flex-1">
										<div className="flex items-center gap-3 mb-2">
											<span className="text-2xl">
												{
													severityIcons[
														err.severity as keyof typeof severityIcons
													]
												}
											</span>
											<h3 className="text-lg font-semibold text-heading">
												{err.error_pattern}
											</h3>
											<span
												className={`px-3 py-1 rounded-full text-xs font-medium border ${
													severityColors[
														err.severity as keyof typeof severityColors
													]
												}`}
											>
												{err.severity.toUpperCase()}
											</span>
										</div>
										<div className="grid grid-cols-2 md:grid-cols-4 gap-4 mt-3">
											<div>
												<p className="text-xs text-muted uppercase">
													Occurrences
												</p>
												<p className="text-lg font-semibold text-foreground">
													{err.occurrences}
												</p>
											</div>
											<div>
												<p className="text-xs text-muted uppercase">
													Affected Users
												</p>
												<p className="text-lg font-semibold text-foreground">
													{err.affected_users}
												</p>
											</div>
											<div>
												<p className="text-xs text-muted uppercase">
													Last Seen
												</p>
												<p className="text-sm text-subheading">
													{new Date(err.last_seen).toLocaleDateString()}
												</p>
											</div>
										</div>
									</div>
								</div>
							</div>
						))}
					</div>
				) : (
					<div className="text-center py-12">
						<div className="inline-flex items-center justify-center w-16 h-16 rounded-full bg-status-success-bg mb-4">
							<svg
								className="w-8 h-8 text-status-success-icon"
								fill="none"
								stroke="currentColor"
								viewBox="0 0 24 24"
								role="img"
								aria-label="No errors"
							>
								<path
									strokeLinecap="round"
									strokeLinejoin="round"
									strokeWidth={2}
									d="M5 13l4 4L19 7"
								/>
							</svg>
						</div>
						<p className="text-lg font-medium text-foreground mb-1">
							No recurring errors found!
						</p>
						<p className="text-sm text-muted">
							Great job! Your team hasn't encountered any recurring errors in
							the selected time period.
						</p>
					</div>
				)}
			</AnalyticsCard>

			{/* Error Insights */}
			{errors && errors.length > 0 && (
				<div className="grid grid-cols-1 md:grid-cols-2 gap-6">
					<AnalyticsCard className="bg-status-error-bg border-status-error-border">
						<div className="flex items-start gap-4">
							<div className="p-3 rounded-lg bg-status-error-bg">
								<AlertTriangle className="h-6 w-6 text-status-error-icon" />
							</div>
							<div className="flex-1">
								<h3 className="text-lg font-semibold text-heading mb-2">
									Action Recommended
								</h3>
								<p className="text-sm text-subheading mb-3">
									You have {highSeverityCount} high-severity error
									{highSeverityCount !== 1 ? "s" : ""} that may require
									immediate attention.
								</p>
								{highSeverityCount > 0 && (
									<p className="text-xs text-muted">
										Consider scheduling a team discussion to address these
										issues.
									</p>
								)}
							</div>
						</div>
					</AnalyticsCard>

					<AnalyticsCard className="bg-status-info-bg border-status-info-border">
						<div className="flex items-start gap-4">
							<div className="p-3 rounded-lg bg-status-info-bg">
								<Users className="h-6 w-6 text-accent" />
							</div>
							<div className="flex-1">
								<h3 className="text-lg font-semibold text-heading mb-2">
									Knowledge Sharing
								</h3>
								<p className="text-sm text-subheading mb-3">
									{errors.filter((e) => e.affected_users > 1).length} error type
									{errors.filter((e) => e.affected_users > 1).length !== 1
										? "s"
										: ""}{" "}
									affecting multiple developers.
								</p>
								<p className="text-xs text-muted">
									Share solutions in team channels to help everyone learn.
								</p>
							</div>
						</div>
					</AnalyticsCard>
				</div>
			)}
		</div>
	);
}

