import { ChevronRight } from "lucide-react";
import { useMemo } from "react";
import { Link, useLocation } from "react-router-dom";
import { useAnalyticsQuery } from "@/hooks/useAnalyticsQuery";
import { formatUsername } from "@/lib/format";
import { orpc } from "@/lib/orpc";

const segmentLabels: Record<string, string> = {
	dashboard: "Overview",
	developers: "Developers",
	projects: "Projects",
	roi: "ROI & Business Value",
	sessions: "Sessions",
	learnings: "Learnings",
	errors: "Errors",
	invitations: "Invitations",
	profile: "Profile",
};

export function Breadcrumb() {
	const { pathname } = useLocation();
	const segments = pathname.split("/").filter(Boolean);

	const hasDeveloperDetail =
		segments.includes("developers") &&
		segments.indexOf("developers") < segments.length - 1;

	const { data: userMappings } = useAnalyticsQuery({
		...orpc.analytics.users.mappings.queryOptions({ input: { days: 30 } }),
		enabled: hasDeveloperDetail,
	});

	const userMap = useMemo(() => {
		const record: Record<string, string> = {};
		if (userMappings) {
			for (const m of userMappings) {
				record[m.user_id] = m.username;
			}
		}
		return record;
	}, [userMappings]);

	const crumbs = segments.map((segment, index) => {
		const href = `/${segments.slice(0, index + 1).join("/")}`;
		const prevSegment = index > 0 ? segments[index - 1] : null;
		const isDeveloperUserId = prevSegment === "developers";
		const label = isDeveloperUserId
			? formatUsername(segment, userMap)
			: segmentLabels[segment] || decodeURIComponent(segment);
		const isLast = index === segments.length - 1;

		return { href, label, isLast };
	});

	return (
		<nav className="flex shrink-0 items-center gap-1 text-xs text-muted h-10 px-8 bg-surface border-b border-border">
			{crumbs.map((crumb, index) => (
				<span key={crumb.href} className="flex items-center gap-1">
					{index > 0 && <ChevronRight className="h-3 w-3" />}
					{crumb.isLast ? (
						<span className="text-subheading">{crumb.label}</span>
					) : (
						<Link
							to={crumb.href}
							className="hover:text-foreground transition-colors"
						>
							{crumb.label}
						</Link>
					)}
				</span>
			))}
		</nav>
	);
}

