27→
28→	const { data: userMappings } = useAnalyticsQuery({
29→		...orpc.analytics.users.mappings.queryOptions({ input: { days: 30 } }),
30→		enabled: hasDeveloperDetail,
31→	});
32→
33→	const userMap = useMemo(() => {
34→		const record: Record<string, string> = {};
35→		if (userMappings) {
36→			for (const m of userMappings) {
37→				record[m.user_id] = m.username;
38→			}
39→		}
40→		return record;
41→	}, [userMappings]);
42→
43→	const crumbs = segments.map((segment, index) => {
44→		const href = `/${segments.slice(0, index + 1).join("/")}`;
45→		const prevSegment = index > 0 ? segments[index - 1] : null;
46→		const isDeveloperUserId = prevSegment === "developers";
47→		const label = isDeveloperUserId
48→			? formatUsername(segment, userMap)
