  1→import type { ErrorTrendDataPoint } from "@rudel/api-routes";
  2→import { useMemo } from "react";
  3→import {
  4→	Area,
  5→	AreaChart,
  6→	CartesianGrid,
  7→	Legend,
  8→	Line,
  9→	LineChart,
 10→	ResponsiveContainer,
 11→	Tooltip,
 12→	XAxis,
 13→	YAxis,
 14→} from "recharts";
 15→import {
 16→	Select,
 17→	SelectContent,
 18→	SelectItem,
 19→	SelectTrigger,
 20→	SelectValue,
 21→} from "@/components/ui/select";
 22→import { useChartTheme } from "@/hooks/useChartTheme";
 23→
 24→interface ErrorTrendChartProps {
 25→	data: ErrorTrendDataPoint[];
 26→	metric:
 27→		| "avg_errors_per_interaction"
 28→		| "avg_errors_per_session"
 29→		| "total_errors";
 30→	splitBy: "repository" | "user_id" | "model";
 31→	onMetricChange: (
 32→		metric:
 33→			| "avg_errors_per_interaction"
 34→			| "avg_errors_per_session"
 35→			| "total_errors",
 36→	) => void;
 37→	onSplitByChange: (splitBy: "repository" | "user_id" | "model") => void;
 38→	userMap?: Map<string, string>;
 39→}
 40→
 41→const COLORS = [
 42→	"#ef4444",
 43→	"#f59e0b",
 44→	"#10b981",
 45→	"#3b82f6",
 46→	"#8b5cf6",
 47→	"#ec4899",
 48→	"#06b6d4",
 49→	"#14b8a6",
 50→	"#f97316",
 51→	"#6366f1",
 52→];
 53→
 54→const METRIC_LABELS: Record<string, string> = {
 55→	avg_errors_per_interaction: "Avg Errors per Interaction",
 56→	avg_errors_per_session: "Avg Errors per Session",
 57→	total_errors: "Total Errors",
 58→};
 59→
 60→const SPLIT_LABELS: Record<string, string> = {
 61→	repository: "by Repository",
 62→	user_id: "by Developer",
 63→	model: "by Model",
 64→};
 65→
 66→export function ErrorTrendChart({
 67→	data,
 68→	metric,
 69→	splitBy,
 70→	onMetricChange,
 71→	onSplitByChange,
 72→	userMap,
 73→}: ErrorTrendChartProps) {
 74→	const { tooltipBg, tooltipBorder, gridStroke } = useChartTheme();
 75→
 76→	const seriesKeys = useMemo(() => {
 77→		if (data.length === 0) return [];
 78→		const keys = new Set<string>();
 79→		for (const item of data) {
 80→			keys.add(item.dimension);
 81→		}
 82→		return Array.from(keys).sort();
 83→	}, [data]);
 84→
 85→	const chartData = useMemo(() => {
 86→		if (data.length === 0) return [];
 87→
 88→		const allDates = Array.from(new Set(data.map((item) => item.date))).sort();
 89→		if (allDates.length === 0) return [];
 90→
 91→		const minDate = new Date(allDates[0]);
 92→		const maxDate = new Date(allDates[allDates.length - 1]);
 93→		const dateRange: string[] = [];
 94→
 95→		for (let d = new Date(minDate); d <= maxDate; d.setDate(d.getDate() + 1)) {
 96→			dateRange.push(d.toISOString().split("T")[0]);
 97→		}
 98→
 99→		const dateMap = new Map<string, Record<string, unknown>>();
100→
101→		for (const dateKey of dateRange) {
102→			const dateData: Record<string, unknown> = {
103→				date: dateKey,
104→				displayDate: new Date(dateKey).toLocaleDateString("en-US", {
105→					month: "short",
106→					day: "numeric",
107→				}),
108→			};
109→			for (const key of seriesKeys) {
110→				dateData[key] = 0;
111→			}
112→			dateMap.set(dateKey, dateData);
113→		}
114→
115→		for (const item of data) {
116→			const dateKey = item.date;
117→			const dateData = dateMap.get(dateKey);
118→			if (dateData) {
119→				dateData[item.dimension] = item[metric];
120→			}
121→		}
122→
123→		return Array.from(dateMap.values()).sort((a, b) =>
124→			(a.date as string).localeCompare(b.date as string),
125→		);
126→	}, [data, metric, seriesKeys]);
127→
128→	const getDisplayName = (key: string): string => {
129→		if (splitBy === "user_id" && userMap) {
130→			return userMap.get(key) || `${key.substring(0, 12)}...`;
131→		}
132→		return key;
133→	};
134→
135→	return (
136→		<div className="space-y-4">
137→			<div className="flex flex-wrap items-center justify-between gap-4">
138→				<div className="flex items-center gap-2">
139→					<label
140→						htmlFor="error-metric-select"
141→						className="text-sm font-medium text-muted"
142→					>
143→						Metric:
144→					</label>
145→					<Select
146→						value={metric}
147→						onValueChange={(v) => onMetricChange(v as typeof metric)}
148→					>
149→						<SelectTrigger className="w-56">
150→							<SelectValue />
151→						</SelectTrigger>
152→						<SelectContent>
153→							{Object.entries(METRIC_LABELS).map(([key, label]) => (
154→								<SelectItem key={key} value={key}>
155→									{label}
156→								</SelectItem>
157→							))}
158→						</SelectContent>
159→					</Select>
160→				</div>
161→
162→				<div className="flex items-center gap-2">
163→					<label
164→						htmlFor="error-split-select"
165→						className="text-sm font-medium text-muted"
166→					>
167→						Split:
168→					</label>
169→					<Select
170→						value={splitBy}
171→						onValueChange={(v) => onSplitByChange(v as typeof splitBy)}
172→					>
173→						<SelectTrigger className="w-40">
174→							<SelectValue />
175→						</SelectTrigger>
176→						<SelectContent>
177→							{Object.entries(SPLIT_LABELS).map(([key, label]) => (
178→								<SelectItem key={key} value={key}>
179→									{label}
180→								</SelectItem>
181→							))}
182→						</SelectContent>
183→					</Select>
184→				</div>
185→			</div>
186→
187→			<ResponsiveContainer width="100%" height={400}>
188→				{metric === "total_errors" ? (
189→					<AreaChart
190→						data={chartData}
191→						margin={{ top: 10, right: 30, left: 0, bottom: 0 }}
192→					>
193→						<CartesianGrid strokeDasharray="3 3" stroke={gridStroke} />
194→						<XAxis
195→							dataKey="displayDate"
196→							tick={{ fontSize: 12 }}
197→							angle={-45}
198→							textAnchor="end"
199→							height={80}
200→						/>
201→						<YAxis tick={{ fontSize: 12 }} />
202→						<Tooltip
203→							contentStyle={{
204→								backgroundColor: tooltipBg,
205→								border: `1px solid ${tooltipBorder}`,
206→								borderRadius: "8px",
207→								padding: "12px",
208→							}}
209→							formatter={(value, name) => {
210→								const displayName = name ? getDisplayName(String(name)) : "";
211→								return [((value as number) ?? 0).toLocaleString(), displayName];
212→							}}
213→							labelFormatter={(label) => `Date: ${label}`}
214→						/>
215→						<Legend
216→							formatter={(value) => getDisplayName(value)}
217→							wrapperStyle={{ fontSize: "12px" }}
218→						/>
219→						{seriesKeys.map((key, index) => (
220→							<Area
221→								key={key}
222→								type="monotone"
223→								dataKey={key}
224→								name={key}
225→								stackId="1"
226→								stroke={COLORS[index % COLORS.length]}
227→								fill={COLORS[index % COLORS.length]}
228→								fillOpacity={0.6}
229→							/>
230→						))}
231→					</AreaChart>
232→				) : (
233→					<LineChart
234→						data={chartData}
235→						margin={{ top: 10, right: 30, left: 0, bottom: 0 }}
236→					>
237→						<CartesianGrid strokeDasharray="3 3" stroke={gridStroke} />
238→						<XAxis
239→							dataKey="displayDate"
240→							tick={{ fontSize: 12 }}
241→							angle={-45}
242→							textAnchor="end"
243→							height={80}
244→						/>
245→						<YAxis tick={{ fontSize: 12 }} />
246→						<Tooltip
247→							contentStyle={{
248→								backgroundColor: tooltipBg,
249→								border: `1px solid ${tooltipBorder}`,
250→								borderRadius: "8px",
251→								padding: "12px",
252→							}}
253→							formatter={(value, name) => {
254→								const displayName = name ? getDisplayName(String(name)) : "";
255→								return [((value as number) ?? 0).toFixed(2), displayName];
256→							}}
257→							labelFormatter={(label) => `Date: ${label}`}
258→						/>
259→						<Legend
260→							formatter={(value) => getDisplayName(value)}
261→							wrapperStyle={{ fontSize: "12px" }}
262→						/>
263→						{seriesKeys.map((key, index) => (
264→							<Line
265→								key={key}
266→								type="monotone"
267→								dataKey={key}
268→								name={key}
269→								stroke={COLORS[index % COLORS.length]}
270→								strokeWidth={2}
271→								dot={{ r: 4 }}
272→								activeDot={{ r: 6 }}
273→								connectNulls={false}
274→							/>
275→						))}
276→					</LineChart>
277→				)}
278→			</ResponsiveContainer>
279→
280→			{seriesKeys.length === 0 && (
281→				<div className="text-center text-sm text-muted py-4">
282→					No error data available for the selected time period
283→				</div>
284→			)}
285→		</div>
286→	);
287→}
