 21→export function TimelineItem({ learning, userMap }: TimelineItemProps) {
 22→	const [isExpanded, setIsExpanded] = useState(false);
 23→
 24→	// Format date
 25→	const formattedDate = format(new Date(learning.created_at), "MMM dd, yyyy");
 26→	const formattedTime = format(new Date(learning.created_at), "h:mm a");
 27→
 28→	// Truncate text for preview
 29→	const contentPreview =
 30→		learning.content.length > 300
 31→			? `${learning.content.slice(0, 300)}...`
 32→			: learning.content;
