 40→
 41→	// Get type badge color (decorative per-type, keep hardcoded)
 42→	const getTypeBadgeColor = (type: string) => {
 43→		switch (type) {
 44→			case "pattern":
 45→				return "bg-green-100 text-green-700 dark:bg-green-900 dark:text-green-300";
 46→			case "antipattern":
 47→				return "bg-red-100 text-red-700 dark:bg-red-900 dark:text-red-300";
 48→			case "convention":
 49→				return "bg-blue-100 text-blue-700 dark:bg-blue-900 dark:text-blue-300";
 50→			case "fix":
 51→				return "bg-yellow-100 text-yellow-700 dark:bg-yellow-900 dark:text-yellow-300";
 52→			case "preference":
 53→				return "bg-purple-100 text-purple-700 dark:bg-purple-900 dark:text-purple-300";
 54→			default:
 55→				return "bg-muted text-muted-foreground";
 56→		}
 57→	};
