 70→			</div>
 71→
 72→			{/* Learning card */}
 73→			<div className="bg-card border border-border rounded-lg shadow-sm hover:shadow-md transition-shadow">
 74→				{/* Header */}
 75→				<div className="p-4 border-b border-border">
 76→					<div className="flex items-start justify-between gap-4">
 77→						<div className="flex-1 space-y-2">
 78→							{/* Type and Scope badges */}
 79→							<div className="flex flex-wrap items-center gap-2">
 80→								<span
 81→									className={cn(
 82→										"px-2 py-1 text-xs font-medium rounded",
 83→										getTypeBadgeColor(learning.type),
 84→									)}
 85→								>
 86→									{learning.type}
 87→								</span>
 88→								<span className="px-2 py-1 text-xs bg-muted text-muted-foreground rounded font-mono">
 89→									{learning.scope}
 90→								</span>
 91→							</div>
 92→
 93→							{/* Metadata */}
 94→							<div className="flex flex-wrap items-center gap-3 text-xs text-muted-foreground">
 95→								<div className="flex items-center gap-1">
 96→									<User className="w-3 h-3" />
