108→									</span>
109→								)}
110→							</div>
111→
112→							{/* Tags */}
113→							{learning.tags && learning.tags.length > 0 && (
114→								<div className="flex flex-wrap gap-1">
115→									{learning.tags.map((tag, idx) => (
116→										<span
117→											// biome-ignore lint/suspicious/noArrayIndexKey: tags may duplicate
118→											key={`${tag}-${idx}`}
119→											className="px-2 py-0.5 text-xs bg-indigo-100 text-indigo-700 dark:bg-indigo-900 dark:text-indigo-300 rounded"
120→										>
121→											#{tag}
122→										</span>
123→									))}
124→								</div>
125→							)}
126→						</div>
127→
128→						{/* Link to session */}
129→						<Link
130→							to={sessionLink}
131→							className="flex items-center gap-1 px-3 py-1.5 text-sm text-blue-600 dark:text-blue-400 hover:text-blue-700 dark:hover:text-blue-300 hover:bg-blue-50 dark:hover:bg-blue-950 rounded-md transition-colors"
132→						>
133→							<span>View Session</span>
134→							<ExternalLink className="w-3 h-3" />
135→						</Link>
136→					</div>
137→				</div>
138→
139→				{/* Learning content */}
140→				<div className="p-4">
141→					<div className="text-sm text-foreground leading-relaxed whitespace-pre-wrap">
142→						{isExpanded ? learning.content : contentPreview}
143→					</div>
144→
145→					{/* Expand/collapse button */}
146→					{learning.content.length > 300 && (
147→						<button
148→							type="button"
149→							onClick={() => setIsExpanded(!isExpanded)}
150→							className="flex items-center gap-1 text-sm text-blue-600 dark:text-blue-400 hover:text-blue-700 dark:hover:text-blue-300 font-medium mt-3"
151→						>
152→							{isExpanded ? (
