156→								</>
157→							) : (
158→								<>
159→									<ChevronDown className="w-4 h-4" />
160→									Show more
161→								</>
162→							)}
163→						</button>
164→					)}
165→				</div>
166→			</div>
167→		</div>
168→	);
169→}
